  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import { Trans } from 'react-i18next';
  4	import {
  5	  TextVariants,
  6	  Text,
  7	  TextContent,
  8	  Accordion,
  9	  AccordionItem,
 10	  AccordionContent,
 11	  AccordionToggle,
 12	  Checkbox,
 13	  TextInput,
 14	  FormHelperText,
 15	  HelperText,
 16	  HelperTextItem,
 17	  ValidatedOptions,
 18	  NumberInput,
 19	  Label,
 20	  Alert,
 21	  AlertVariant,
 22	} from '@patternfly/react-core';
 23	import { StateAndDispatchProps, RuleActionType, FuncType } from './reducer';
 24	import {
 25	  isInvalidActionsCount,
 26	  isInvalidDeleteCurrent,
 27	  isInvalidDeleteNonCurrent,
 28	  isInvalidDeleteMultiparts,
 29	} from './validations';
 30	import './create-lifecycle-rules.scss';
 31	
 32	enum Actions {
 33	  CURRENT_OBJECTS = 'CURRENT_OBJECTS',
 34	  NONCURRENT_OBJECTS = 'NONCURRENT_OBJECTS',
 35	  INCOMPLETE_UPLOADS = 'INCOMPLETE_UPLOADS',
 36	  EXPIRED_MARKERS = 'EXPIRED_MARKERS',
 37	}
 38	
 39	const ExpiredDeleteMarkers: React.FC<StateAndDispatchProps> = ({
 40	  state,
 41	  dispatch,
 42	}) => {
 43	  const { t } = useCustomTranslation();
 44	
 45	  const deleteExpiredMarkers = state.actions.deleteExpiredMarkers;
 46	  const deleteCurrent = state.actions.deleteCurrent;
 47	
 48	  return (
 49	    <div className="pf-v6-u-ml-xl">
 50	      <Checkbox
 51	        id="expired-delete-marker"
 52	        label={t('Delete expired object delete markers')}
 53	        className="pf-v6-u-mb-md"
 54	        isChecked={deleteExpiredMarkers}
 55	        isDisabled={deleteCurrent.isChecked}
 56	        onChange={(_e, checked) =>
 57	          dispatch({
 58	            type: RuleActionType.RULE_DELETE_MARKERS_ACTION,
 59	            payload: checked,
 60	          })
 61	        }
 62	      />
 63	      {deleteCurrent.isChecked ? (
 64	        <Alert
 65	          variant={AlertVariant.info}
 66	          isInline
 67	          isPlain
 68	          title={t(
 69	            'Delete expired object delete markers cannot be enabled when delete object (i.e expiry current versions) is selected.'
 70	          )}
 71	        />
 72	      ) : (
 73	        <>
 74	          <b>{t('Note:')}</b>
 75	          <br />
 76	          {t(
 77	            'Above object tags and object size filters are not applicable for this rule action. Expired object delete markers will be removed from the bucket regardless of any filters you have configured.'
 78	          )}
 79	        </>
 80	      )}
 81	    </div>
 82	  );
 83	};
 84	
 85	const IncompleteMultipartUploads: React.FC<StateAndDispatchProps> = ({
 86	  state,
 87	  dispatch,
 88	}) => {
 89	  const { t } = useCustomTranslation();
 90	
 91	  const deleteIncompleteMultiparts = state.actions.deleteIncompleteMultiparts;
 92	
 93	  const invalidDeleteMultiparts =
 94	    state.triggerInlineValidations && isInvalidDeleteMultiparts(state);
 95	
 96	  return (
 97	    <div className="pf-v6-u-ml-xl">
 98	      <Checkbox
 99	        id="incomplete-multiparts-delete"
100	        label={t('Delete incomplete multipart uploads')}
101	        className="pf-v6-u-mb-md"
102	        isChecked={deleteIncompleteMultiparts.isChecked}
103	        onChange={(_e, checked) =>
104	          dispatch({
105	            type: RuleActionType.RULE_DELETE_MULTIPARTS_ACTION,
106	            payload: { ...deleteIncompleteMultiparts, isChecked: checked },
107	          })
108	        }
109	        body={
110	          deleteIncompleteMultiparts.isChecked ? (
111	            <div className="pf-v6-u-w-25">
112	              <TextInput
113	                id="incomplete-multiparts-delete-days"
114	                value={deleteIncompleteMultiparts.days}
115	                onChange={(_e, value) =>
116	                  dispatch({
117	                    type: RuleActionType.RULE_DELETE_MULTIPARTS_ACTION,
118	                    payload: {
119	                      ...deleteIncompleteMultiparts,
120	                      days: Math.round(+value || 0),
121	                    },
122	                  })
123	                }
124	                placeholder={t('Enter number of days')}
125	                type="number"
126	                validated={
127	                  invalidDeleteMultiparts
128	                    ? ValidatedOptions.error
129	                    : ValidatedOptions.default
130	                }
131	              />
132	              <FormHelperText>
133	                <HelperText>
134	                  <HelperTextItem
135	                    variant={
136	                      invalidDeleteMultiparts
137	                        ? ValidatedOptions.error
138	                        : ValidatedOptions.default
139	                    }
140	                  >
141	                    {invalidDeleteMultiparts
142	                      ? t('Must be an integer greater than 0.')
143	                      : t('Period of time (in days).')}
144	                  </HelperTextItem>
145	                </HelperText>
146	              </FormHelperText>
147	            </div>
148	          ) : null
149	        }
150	      />
151	      <b>{t('Note:')}</b>
152	      <br />
153	      {t(
154	        'Above object tags and object size filters are not applicable for this rule action. Incomplete multipart uploads will be removed from the bucket regardless of any filters you have configured.'
155	      )}
156	    </div>
157	  );
158	};
159	
160	const NonCurrentObjects: React.FC<StateAndDispatchProps> = ({
161	  state,
162	  dispatch,
163	}) => {
164	  const { t } = useCustomTranslation();
165	
166	  const deleteNonCurrent = state.actions.deleteNonCurrent;
167	  const onNumberInputAction = (
168	    funcType: FuncType,
169	    event?: React.FormEvent<HTMLInputElement>
170	  ) => {
171	    let newRetention: number;
172	    switch (funcType) {
173	      case FuncType.ON_CHANGE: {
174	        newRetention = Math.max(
175	          Math.min(
176	            Math.round(+(event?.target as HTMLInputElement)?.value) || 0,
177	            100
178	          ),
179	          0
180	        );
181	        break;
182	      }
183	      case FuncType.ON_MINUS: {
184	        newRetention = Math.max(deleteNonCurrent.retention - 1, 0);
185	        break;
186	      }
187	      case FuncType.ON_PLUS: {
188	        newRetention = Math.min(deleteNonCurrent.retention + 1, 100);
189	        break;
190	      }
191	    }
192	    dispatch({
193	      type: RuleActionType.RULE_DELETE_NON_CURRENT_ACTION,
194	      payload: {
195	        ...deleteNonCurrent,
196	        retention: newRetention,
197	      },
198	    });
199	  };
200	
201	  const invalidDeleteNonCurrent =
202	    state.triggerInlineValidations && isInvalidDeleteNonCurrent(state);
203	
204	  return (
205	    <Checkbox
206	      id="noncurrent-object-delete"
207	      label={t('Delete noncurrent versions')}
208	      description={t(
209	        'Delete older versions of objects after they become noncurrent (e.g., a new version overwrites them).'
210	      )}
211	      className="pf-v6-u-ml-xl"
212	      isChecked={deleteNonCurrent.isChecked}
213	      onChange={(_e, checked) =>
214	        dispatch({
215	          type: RuleActionType.RULE_DELETE_NON_CURRENT_ACTION,
216	          payload: { ...deleteNonCurrent, isChecked: checked },
217	        })
218	      }
219	      body={
220	        deleteNonCurrent.isChecked ? (
221	          <>
222	            <div className="pf-v6-u-w-25">
223	              <TextInput
224	                id="noncurrent-object-delete-days"
225	                value={deleteNonCurrent.days}
226	                onChange={(_e, value) =>
227	                  dispatch({
228	                    type: RuleActionType.RULE_DELETE_NON_CURRENT_ACTION,
229	                    payload: {
230	                      ...deleteNonCurrent,
231	                      days: Math.round(+value || 0),
232	                    },
233	                  })
234	                }
235	                placeholder={t('Enter number of days')}
236	                type="number"
237	                validated={
238	                  invalidDeleteNonCurrent
239	                    ? ValidatedOptions.error
240	                    : ValidatedOptions.default
241	                }
242	              />
243	              <FormHelperText>
244	                <HelperText>
245	                  <HelperTextItem
246	                    variant={
247	                      invalidDeleteNonCurrent
248	                        ? ValidatedOptions.error
249	                        : ValidatedOptions.default
250	                    }
251	                  >
252	                    {invalidDeleteNonCurrent
253	                      ? t('Must be an integer greater than 0.')
254	                      : t(
255	                          'Period of time (in days) after which a noncurrent versions of object would be deleted since turning noncurrent.'
256	                        )}
257	                  </HelperTextItem>
258	                </HelperText>
259	              </FormHelperText>
260	            </div>
261	
262	            <TextContent className="pf-v6-u-mt-lg">
263	              <Text component={TextVariants.p}>
264	                {t('Preserve object version history (Optional)')}
265	              </Text>
266	              <Text
267	                component={TextVariants.small}
268	                className="s3-lifecycle-action--margin"
269	              >
270	                {t(
271	                  'Keep up to 100 noncurrent versions of objects for version management and rollback. Excess versions will be automatically deleted.'
272	                )}
273	              </Text>
274	            </TextContent>
275	            <NumberInput
276	              value={deleteNonCurrent.retention}
277	              min={0}
278	              max={100}
279	              onMinus={() => onNumberInputAction(FuncType.ON_MINUS)}
280	              onPlus={() => onNumberInputAction(FuncType.ON_PLUS)}
281	              onChange={(e) => onNumberInputAction(FuncType.ON_CHANGE, e)}
282	              className="pf-v6-u-mt-md"
283	            />
284	            <FormHelperText>
285	              <HelperText>
286	                <HelperTextItem>
287	                  {t('Number of noncurrent versions of object.')}
288	                </HelperTextItem>
289	              </HelperText>
290	            </FormHelperText>
291	          </>
292	        ) : null
293	      }
294	    />
295	  );
296	};
297	
298	const CurrentObjects: React.FC<StateAndDispatchProps> = ({
299	  state,
300	  dispatch,
301	}) => {
302	  const { t } = useCustomTranslation();
303	
304	  const deleteCurrent = state.actions.deleteCurrent;
305	
306	  const invalidDeleteCurrent =
307	    state.triggerInlineValidations && isInvalidDeleteCurrent(state);
308	
309	  return (
310	    <Checkbox
311	      id="current-object-delete"
312	      label={t('Delete object (i.e., expiry current versions)')}
313	      description={t(
314	        'When deleting for versioned buckets a delete marker is added and the current version of the object is retained as noncurrent version, for non-versioned buckets object deletion is permanent.'
315	      )}
316	      className="pf-v6-u-ml-xl"
317	      isChecked={deleteCurrent.isChecked}
318	      onChange={(_e, checked) => {
319	        dispatch({
320	          type: RuleActionType.RULE_DELETE_CURRENT_ACTION,
321	          payload: { ...deleteCurrent, isChecked: checked },
322	        });
323	        dispatch({
324	          type: RuleActionType.RULE_DELETE_MARKERS_ACTION,
325	          payload: false,
326	        });
327	      }}
328	      body={
329	        deleteCurrent.isChecked ? (
330	          <div className="pf-v6-u-w-25">
331	            <TextInput
332	              id="current-object-delete-days"
333	              value={deleteCurrent.days}
334	              onChange={(_e, value) =>
335	                dispatch({
336	                  type: RuleActionType.RULE_DELETE_CURRENT_ACTION,
337	                  payload: { ...deleteCurrent, days: Math.round(+value || 0) },
338	                })
339	              }
340	              placeholder={t('Enter number of days')}
341	              type="number"
342	              validated={
343	                invalidDeleteCurrent
344	                  ? ValidatedOptions.error
345	                  : ValidatedOptions.default
346	              }
347	            />
348	            <FormHelperText>
349	              <HelperText>
350	                <HelperTextItem
351	                  variant={
352	                    invalidDeleteCurrent
353	                      ? ValidatedOptions.error
354	                      : ValidatedOptions.default
355	                  }
356	                >
357	                  {invalidDeleteCurrent
358	                    ? t('Must be an integer greater than 0.')
359	                    : t(
360	                        'Period of time (in days) after which an object would be deleted since its creation.'
361	                      )}
362	                </HelperTextItem>
363	              </HelperText>
364	            </FormHelperText>
365	          </div>
366	        ) : null
367	      }
368	    />
369	  );
370	};
371	
372	export const RuleActions: React.FC<StateAndDispatchProps> = ({
373	  state,
374	  dispatch,
375	}) => {
376	  const { t } = useCustomTranslation();
377	
378	  const [expanded, setExpanded] = React.useState<Actions>(null);
379	
380	  const onToggle = (id: Actions) => {
381	    if (id === expanded) {
382	      setExpanded(null);
383	    } else {
384	      setExpanded(id);
385	    }
386	  };
387	
388	  const validate = state.triggerInlineValidations;
389	  const [invalidActionsCount, actionsCount] = isInvalidActionsCount(state);
390	  const invalidDeleteCurrent = validate && isInvalidDeleteCurrent(state);
391	  const invalidDeleteNonCurrent = validate && isInvalidDeleteNonCurrent(state);
392	  const invalidDeleteMultiparts = validate && isInvalidDeleteMultiparts(state);
393	
394	  return (
395	    <>
396	      <TextContent>
397	        <Text component={TextVariants.h2}>{t('Lifecycle rule actions')}</Text>
398	        <Text component={TextVariants.small}>
399	          {t(
400	            'Define what happens to objects in an S3 bucket during their lifecycle.'
401	          )}
402	        </Text>
403	        <Text component={TextVariants.small} className="pf-v6-u-my-sm">
404	          <Trans t={t} values={{ actionsCount }}>
405	            You have defined{' '}
406	            <strong>{{ actionsCount }} lifecycle rules.</strong>
407	          </Trans>
408	        </Text>
409	      </TextContent>
410	      {validate && invalidActionsCount && (
411	        <Alert
412	          variant={AlertVariant.danger}
413	          isInline
414	          isPlain
415	          title={t('At least one action needs to be defined for the rule.')}
416	          className="s3-lifecycle-validation--font-weight"
417	        />
418	      )}
419	
420	      <Accordion togglePosition="start" className="s3-lifecycle--margin">
421	        <AccordionItem>
422	          <AccordionToggle
423	            onClick={() => {
424	              onToggle(Actions.CURRENT_OBJECTS);
425	            }}
426	
427	            id={Actions.CURRENT_OBJECTS}
428	          >
429	            <Text
430	              component={TextVariants.h3}
431	              className="pf-v5-u-text-align-left"
432	            >
433	              <span>
434	                {t('Objects')}
435	                {state.actions.deleteCurrent.isChecked && (
436	                  <Label
437	                    variant="outline"
438	                    color="blue"
439	                    className="pf-v6-u-mx-xs"
440	                  >
441	                    {t('Selected')}
442	                  </Label>
443	                )}
444	                {invalidDeleteCurrent && (
445	                  <Label
446	                    variant="outline"
447	                    color="red"
448	                    className="pf-v6-u-mx-xs"
449	                  >
450	                    {t('Details needed')}
451	                  </Label>
452	                )}
453	              </span>
454	            </Text>
455	            <Text
456	              component={TextVariants.small}
457	              className={invalidDeleteCurrent && 's3-lifecycle--margin'}
458	            >
459	              {t('Delete an object after a specified time.')}
460	            </Text>
461	          </AccordionToggle>
462	          <AccordionContent
463	            id={Actions.CURRENT_OBJECTS}
464	
465	          >
466	            <CurrentObjects state={state} dispatch={dispatch} />
467	          </AccordionContent>
468	        </AccordionItem>
469	
470	        <AccordionItem>
471	          <AccordionToggle
472	            onClick={() => {
473	              onToggle(Actions.NONCURRENT_OBJECTS);
474	            }}
475	
476	            id={Actions.NONCURRENT_OBJECTS}
477	          >
478	            <Text
479	              component={TextVariants.h3}
480	              className="pf-v5-u-text-align-left"
481	            >
482	              <span>
483	                {t('Noncurrent versions of objects')}
484	                {state.actions.deleteNonCurrent.isChecked && (
485	                  <Label
486	                    variant="outline"
487	                    color="blue"
488	                    className="pf-v6-u-mx-xs"
489	                  >
490	                    {t('Selected')}
491	                  </Label>
492	                )}
493	                {invalidDeleteNonCurrent && (
494	                  <Label
495	                    variant="outline"
496	                    color="red"
497	                    className="pf-v6-u-mx-xs"
498	                  >
499	                    {t('Details needed')}
500	                  </Label>
501	                )}
502	              </span>
503	            </Text>
504	            <Text component={TextVariants.small}>
505	              {t(
506	                'Delete older versions of objects after they become noncurrent (e.g., a new version overwrites them). Applies only to versioned buckets.'
507	              )}
508	            </Text>
509	          </AccordionToggle>
510	          <AccordionContent
511	            id={Actions.NONCURRENT_OBJECTS}
512	
513	          >
514	            <NonCurrentObjects state={state} dispatch={dispatch} />
515	          </AccordionContent>
516	        </AccordionItem>
517	
518	        <AccordionItem>
519	          <AccordionToggle
520	            onClick={() => {
521	              onToggle(Actions.INCOMPLETE_UPLOADS);
522	            }}
523	
524	            id={Actions.INCOMPLETE_UPLOADS}
525	          >
526	            <Text
527	              component={TextVariants.h3}
528	              className="pf-v5-u-text-align-left"
529	            >
530	              <span>
531	                {t('Incomplete multipart uploads')}
532	                {state.actions.deleteIncompleteMultiparts.isChecked && (
533	                  <Label
534	                    variant="outline"
535	                    color="blue"
536	                    className="pf-v6-u-mx-xs"
537	                  >
538	                    {t('Selected')}
539	                  </Label>
540	                )}
541	                {invalidDeleteMultiparts && (
542	                  <Label
543	                    variant="outline"
544	                    color="red"
545	                    className="pf-v6-u-mx-xs"
546	                  >
547	                    {t('Details needed')}
548	                  </Label>
549	                )}
550	              </span>
551	            </Text>
552	            <Text component={TextVariants.small}>
553	              {t(
554	                'Clean up abandoned uploads to prevent accruing unnecessary storage costs. Targets multipart uploads that were initiated but never completed.'
555	              )}
556	            </Text>
557	          </AccordionToggle>
558	          <AccordionContent
559	            id={Actions.INCOMPLETE_UPLOADS}
560	
561	          >
562	            <IncompleteMultipartUploads state={state} dispatch={dispatch} />
563	          </AccordionContent>
564	        </AccordionItem>
565	
566	        <AccordionItem>
567	          <AccordionToggle
568	            onClick={() => {
569	              onToggle(Actions.EXPIRED_MARKERS);
570	            }}
571	
572	            id={Actions.EXPIRED_MARKERS}
573	          >
574	            <Text
575	              component={TextVariants.h3}
576	              className="pf-v5-u-text-align-left"
577	            >
578	              {t('Expired object delete markers')}
579	              {state.actions.deleteExpiredMarkers && (
580	                <Label variant="outline" color="blue" className="pf-v6-u-mx-xs">
581	                  {t('Selected')}
582	                </Label>
583	              )}
584	            </Text>
585	            <Text component={TextVariants.small}>
586	              {t(
587	                'Remove unnecessary delete markers that clutter bucket listings and do not serve a purpose. Targets delete markers in versioned buckets that do not have any associated object versions (orphaned delete markers).'
588	              )}
589	            </Text>
590	          </AccordionToggle>
591	          <AccordionContent
592	            id={Actions.EXPIRED_MARKERS}
593	
594	          >
595	            <ExpiredDeleteMarkers state={state} dispatch={dispatch} />
596	          </AccordionContent>
597	        </AccordionItem>
598	      </Accordion>
599	    </>
600	  );
601	};

