227	                  dispatch({
228	                    type: RuleActionType.RULE_DELETE_NON_CURRENT_ACTION,
229	                    payload: {
230	                      ...deleteNonCurrent,
231	                      days: Math.round(+value || 0),
232	                    },
233	                  })
234	                }
235	                placeholder={t('Enter number of days')}
236	                type="number"
237	                validated={
238	                  invalidDeleteNonCurrent
239	                    ? ValidatedOptions.error
240	                    : ValidatedOptions.default
241	                }
242	              />
243	              <FormHelperText>
244	                <HelperText>
245	                  <HelperTextItem
246	                    variant={
247	                      invalidDeleteNonCurrent
248	                        ? ValidatedOptions.error
249	                        : ValidatedOptions.default
250	                    }
251	                  >
252	                    {invalidDeleteNonCurrent
253	                      ? t('Must be an integer greater than 0.')
254	                      : t(
255	                          'Period of time (in days) after which a noncurrent versions of object would be deleted since turning noncurrent.'
256	                        )}
257	                  </HelperTextItem>
258	                </HelperText>
259	              </FormHelperText>
260	            </div>
261	
262	            <TextContent className="pf-v6-u-mt-lg">
263	              <Text component={TextVariants.p}>
